const materialVolume = inputs.materialVolume;
const materialLifespan = inputs.materialLifespan;
const embodiedCarbonPerM3 = inputs.embodiedCarbonPerM3;
const initialCostPerM3 = inputs.initialCostPerM3;
const maintenanceCostAnnualPerM3 = inputs.maintenanceCostAnnualPerM3;
const maintenanceCarbonAnnualPerM3 = inputs.maintenanceCarbonAnnualPerM3;
const endOfLifeScenario = inputs.endOfLifeScenario;
const eolCostPerM3 = inputs.eolCostPerM3;
const eolCarbonImpactPerM3 = inputs.eolCarbonImpactPerM3;

// Handle edge cases for zero or negative lifespan/volume
if (materialVolume <= 0 || materialLifespan <= 0) {
    return {
        totalLifecycleCost: 0,
        totalLifecycleCarbon: 0,
        annualizedLifecycleCost: 0,
        annualizedLifecycleCarbon: 0
    };
}

// 1. Initial / Embodied Phase (A1-A3)
// These costs/impacts occur at the beginning of the lifecycle.
const initialCost = materialVolume * initialCostPerM3;
const embodiedCarbon = materialVolume * embodiedCarbonPerM3;

// 2. Use / Operational Phase (B1-B5)
// These costs/impacts are recurring over the material's lifespan.
const totalMaintenanceCost = materialVolume * maintenanceCostAnnualPerM3 * materialLifespan;
const totalMaintenanceCarbon = materialVolume * maintenanceCarbonAnnualPerM3 * materialLifespan;

// 3. End-of-Life Phase (C1-C4)
// These costs/impacts occur at the end of the material's lifecycle.
// eolCostPerM3 and eolCarbonImpactPerM3 are assumed to be provided by the user for the selected scenario.
// For recycling/reuse, these values can be negative (revenue/credit).
const endOfLifeCost = materialVolume * eolCostPerM3;
const endOfLifeCarbon = materialVolume * eolCarbonImpactPerM3;

// Calculate Total Lifecycle Impacts
const totalLifecycleCost = initialCost + totalMaintenanceCost + endOfLifeCost;
const totalLifecycleCarbon = embodiedCarbon + totalMaintenanceCarbon + endOfLifeCarbon;

// Calculate Annualized Lifecycle Impacts
const annualizedLifecycleCost = totalLifecycleCost / materialLifespan;
const annualizedLifecycleCarbon = totalLifecycleCarbon / materialLifespan;

return {
    totalLifecycleCost: totalLifecycleCost,
    totalLifecycleCarbon: totalLifecycleCarbon,
    annualizedLifecycleCost: annualizedLifecycleCost,
    annualizedLifecycleCarbon: annualizedLifecycleCarbon
};
